#[derive(Clone)]
pub struct Announcements {
    client: Client,
}

impl Announcements {
    /// Wraps an already-built client (e.g. from `ClientBuilder`).
    pub fn from_client(client: Client) -> Self {
        Self { client }
    }

    /// Get latest announcements from centralized exchanges
    pub async fn announcements(
        &self,
        options: CexAnnouncementsOptions,
    ) -> Result<CexAnnouncementsResponse> {
        let mut parameters = BTreeMap::new();
        if let Some(v) = options.page {
            parameters.insert("page".to_string(), v.to_string());
        }
        if let Some(v) = options.limit {
            parameters.insert("limit".to_string(), v.to_string());
        }
        if let Some(v) = options.sort {
            parameters.insert("sort".to_string(), v.to_string());
        }
        if let Some(v) = options.key {
            parameters.insert("key".to_string(), v.to_string());
        }
        if let Some(v) = options.exchange {
            parameters.insert("exchange".to_string(), v.to_string());
        }
        if let Some(v) = options.category {
            parameters.insert("category".to_string(), v.to_string());
        }
        self.client
            .get("/api/v1/cex/announcements", Some(parameters))
            .await
    }
}

#[derive(Default, Clone)]
pub struct CexAnnouncementsOptions {
    /// Page number (e.g. `1`)
    pub page: Option<i64>,
    /// Page size (e.g. `100`)
    pub limit: Option<i64>,
    /// Specifies sort (e.g. `asc`)
    pub sort: Option<CexAnnouncementsSort>,
    /// Specifies key to sort by (e.g. `title`)
    pub key: Option<CexAnnouncementsKey>,
    /// Specifies exchange(s), separated by , (e.g. `binance`)
    pub exchange: Option<String>,
    /// Specifies category(s), separated by , (e.g. `listing`)
    pub category: Option<CexAnnouncementsCategory>,
}

impl CexAnnouncementsOptions {
    pub fn new() -> Self {
        CexAnnouncementsOptions {
            page: None,
            limit: None,
            sort: None,
            key: None,
            exchange: None,
            category: None,
        }
    }

    pub fn page(mut self, page: i64) -> Self {
        self.page = Some(page);
        self
    }

    pub fn limit(mut self, limit: i64) -> Self {
        self.limit = Some(limit);
        self
    }

    pub fn sort(mut self, sort: CexAnnouncementsSort) -> Self {
        self.sort = Some(sort);
        self
    }

    pub fn key(mut self, key: CexAnnouncementsKey) -> Self {
        self.key = Some(key);
        self
    }

    pub fn exchange(mut self, exchange: impl Into<String>) -> Self {
        self.exchange = Some(exchange.into());
        self
    }

    pub fn category(mut self, category: CexAnnouncementsCategory) -> Self {
        self.category = Some(category);
        self
    }
}

